/*
 * Shared-Memory Parallel Programming with OpenMP
 * 
 * In shared-memory systems, all threads have access to the same
 * global memory address space. This program demonstrates:
 * - Parallel for loops with shared data
 * - Critical sections for synchronized access
 * - Reduction for efficient parallel accumulation
 * 
 * Compile: gcc -fopenmp -o openmp_demo openmp_demo.c
 */

#include <stdio.h>
#include <omp.h>
#include <math.h>

#define N 1000000

int main() {
 int i;
 double sum = 0.0;
 double start_time, end_time;

 // Allocate shared array - all threads can access this
 double *shared_array = (double*)malloc(N * sizeof(double));

 // Initialize array - all threads will access this
 #pragma omp parallel for
 for (i = 0; i < N; i++) {
 shared_array[i] = (double)(i + 1);
 }

 printf("==================================================\n");
 printf("Shared-Memory Parallel Computing with OpenMP\n");
 printf("==================================================\n");
 printf("Number of threads available: %d\n", omp_get_max_threads());

 /*
 * METHOD 1: Using Critical Section (Explicit Synchronization)
 * All threads write to shared 'sum' variable - requires synchronization
 */
 sum = 0.0;
 start_time = omp_get_wtime();

 #pragma omp parallel for
 for (i = 0; i < N; i++) {
 double temp = sqrt(shared_array[i]) * log(shared_array[i]);

 // Critical section ensures only one thread updates sum at a time
 // This is necessary because multiple threads write to shared memory
 #pragma omp critical
 {
 sum += temp;
 }
 }

 end_time = omp_get_wtime();
 printf("\nMethod 1 (Critical Section):\n");
 printf(" Result: %.6f\n", sum);
 printf(" Time: %.4f seconds\n", end_time - start_time);

 /*
 * METHOD 2: Using Reduction (Optimized Synchronization)
 * OpenMP automatically handles synchronization for reduction
 * Each thread has a private copy, combined at the end
 */
 sum = 0.0;
 start_time = omp_get_wtime();

 #pragma omp parallel for reduction(+:sum)
 for (i = 0; i < N; i++) {
 double temp = sqrt(shared_array[i]) * log(shared_array[i]);
 sum += temp; // Each thread adds to its private copy
 }

 end_time = omp_get_wtime();
 printf("\nMethod 2 (Reduction):\n");
 printf(" Result: %.6f\n", sum);
 printf(" Time: %.4f seconds\n", end_time - start_time);

 /*
 * METHOD 3: Array of results with manual combination
 * Demonstrates false sharing and cache coherence considerations
 */
 int num_threads = omp_get_max_threads();
 double *local_sums = (double*)calloc(num_threads, sizeof(double));

 start_time = omp_get_wtime();

 #pragma omp parallel
 {
 int thread_id = omp_get_thread_num();
 // Each thread has private thread_id, works on shared array
 // but stores result in thread-local portion of shared array
 #pragma omp for
 for (i = 0; i < N; i++) {
 local_sums[thread_id] += sqrt(shared_array[i]) * log(shared_array[i]);
 }
 }

 // Combine local results (this is the aggregation phase)
 for (i = 0; i < num_threads; i++) {
 sum += local_sums[i];
 }

 end_time = omp_get_wtime();
 printf("\nMethod 3 (Manual reduction):\n");
 printf(" Result: %.6f\n", sum);
 printf(" Time: %.4f seconds\n", end_time - start_time);

 printf("\nKey Shared-Memory Concepts Demonstrated:\n");
 printf(" - Global address space: All threads access shared_array\n");
 printf(" - Implicit data sharing: No explicit message passing\n");
 printf(" - Synchronization: Critical sections prevent race conditions\n");
 printf(" - Cache coherence: Hardware maintains consistency\n");

 free(shared_array);
 free(local_sums);

 return 0;
}

/*
 * Distributed-Memory Parallel Programming with MPI
 * 
 * In distributed-memory systems, each process has its own local memory.
 * There is no global address space - data must be explicitly passed via messages.
 * This program demonstrates:
 * - Data partitioning across processes (scatter)
 * - Local computation on each process's local data
 * - Explicit message passing for result aggregation (reduce)
 * - Broadcasting final results to all processes
 * 
 * Compile: mpicc -o mpi_demo mpi_demo.c -lm
 * Run: mpirun -np 4 ./mpi_demo
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <mpi.h>
#include <math.h>

#define N 1000000

int main(int argc, char *argv[]) {
 int rank, num_procs;
 int local_n;
 double *global_data = NULL;
 double *local_data = NULL;
 double local_sum = 0.0;
 double global_sum = 0.0;
 double start_time, end_time;

 // Initialize MPI - each process gets its rank and total count
 MPI_Init(&argc, &argv);
 MPI_Comm_rank(MPI_COMM_WORLD, &rank);
 MPI_Comm_size(MPI_COMM_WORLD, &num_procs);

 printf("Process %d of %d starting...\n", rank, num_procs);

 /*
 * DISTRIBUTED MEMORY: Data is partitioned across processes
 * Each process will have local_n elements in its private memory
 */
 local_n = N / num_procs;

 // Allocate LOCAL memory for each process (private address space)
 local_data = (double*)malloc(local_n * sizeof(double));

 if (rank == 0) {
 // Root process allocates and initializes GLOBAL data
 global_data = (double*)malloc(N * sizeof(double));
 for (int i = 0; i < N; i++) {
 global_data[i] = (double)(i + 1);
 }

 printf("==================================================\n");
 printf("Distributed-Memory Parallel Computing with MPI\n");
 printf("==================================================\n");
 printf("Total elements: %d, Processes: %d\n", N, num_procs);
 printf("Elements per process (local_n): %d\n", local_n);
 }

 /*
 * STEP 1: Data Distribution (like MPI_Scatter)
 * Explicitly send data from root to all other processes
 * This is communication - inherent to distributed memory
 */
 start_time = MPI_Wtime();

 // In real MPI, use MPI_Scatter; here we show manual distribution
 if (rank == 0) {
 // Root sends chunks to all other processes
 for (int dest = 1; dest < num_procs; dest++) {
 MPI_Send(&global_data[dest * local_n], local_n, MPI_DOUBLE, 
 dest, 0, MPI_COMM_WORLD);
 }
 // Root keeps its chunk
 memcpy(local_data, global_data, local_n * sizeof(double));
 } else {
 // All other processes receive their chunk
 MPI_Recv(local_data, local_n, MPI_DOUBLE, 0, 0, 
 MPI_COMM_WORLD, MPI_STATUS_IGNORE);
 }

 /*
 * STEP 2: Local Computation
 * Each process works on its LOCAL data only (fast access)
 * No synchronization needed during computation phase
 */
 printf("Process %d: Computing on local data (size %d)\n", rank, local_n);

 for (int i = 0; i < local_n; i++) {
 local_sum += sqrt(local_data[i]) * log(local_data[i]);
 }

 printf("Process %d: Local sum = %.6f\n", rank, local_sum);

 /*
 * STEP 3: Result Aggregation (like MPI_Reduce)
 * Explicit message passing to combine results at root
 */
 if (rank == 0) {
 global_sum = local_sum;
 // Receive local sums from all other processes
 for (int src = 1; src < num_procs; src++) {
 double temp;
 MPI_Recv(&temp, 1, MPI_DOUBLE, src, 1, 
 MPI_COMM_WORLD, MPI_STATUS_IGNORE);
 global_sum += temp;
 printf("Process 0: Received sum %.6f from process %d\n", temp, src);
 }
 } else {
 // Send local result to root process
 MPI_Send(&local_sum, 1, MPI_DOUBLE, 0, 1, MPI_COMM_WORLD);
 }

 /*
 * STEP 4: Broadcast Final Result (like MPI_Bcast)
 * All processes need the final result - explicit communication
 */
 MPI_Bcast(&global_sum, 1, MPI_DOUBLE, 0, MPI_COMM_WORLD);

 end_time = MPI_Wtime();

 if (rank == 0) {
 printf("\nFinal Global Sum: %.6f\n", global_sum);
 printf("Total Time: %.4f seconds\n", end_time - start_time);
 printf("\nKey Distributed-Memory Concepts Demonstrated:\n");
 printf(" - Private address space: Each process has local_data\n");
 printf(" - Explicit communication: MPI_Send/MPI_Recv for data transfer\n");
 printf(" - No shared memory: No race conditions, but more complex\n");
 printf(" - Network latency: Communication overhead visible in timing\n");
 }

 // Cleanup - each process frees its LOCAL memory
 free(local_data);
 if (rank == 0) {
 free(global_data);
 }

 MPI_Finalize();
 return 0;
}
